        bool temperature_stale = false;
        bool level_stale = false;

        if (controller->has_valid_temperature) {
            temperature_stale = controller_sensor_is_stale(input.now_ms, controller->last_temperature_ms);
        }
        if (controller->has_valid_level) {
            level_stale = controller_sensor_is_stale(input.now_ms, controller->last_level_ms);
        }

        timed_out = temperature_stale || level_stale;

        if (!controller->has_valid_temperature || !controller->has_valid_level || timed_out) {
            controller_set_safe_idle(controller);
        } else {
            controller_apply_policy(controller, previous_heater_on);
        }
